package main

import (
	"context"
	"net"
	"testing"
	"time"

	grpc_middleware "github.com/grpc-ecosystem/go-grpc-middleware"
	"github.com/stretchr/testify/require"
	auth "go.flipt.io/flipt/internal/server/auth"
	middleware "go.flipt.io/flipt/internal/server/middleware/grpc"
	storageauth "go.flipt.io/flipt/internal/storage/auth"
	"go.flipt.io/flipt/internal/storage/auth/memory"
	authrpc "go.flipt.io/flipt/rpc/flipt/auth"
	"go.uber.org/zap/zaptest"
	"google.golang.org/grpc"
	"google.golang.org/grpc/metadata"
	"google.golang.org/grpc/test/bufconn"
	"google.golang.org/protobuf/types/known/emptypb"
	"google.golang.org/protobuf/types/known/timestamppb"
)

// TestRegression_CookieBasedTokenExtraction demonstrates the bug where
// authentication tokens stored in HTTP cookies are not extracted by the
// authentication middleware. The middleware only accepts tokens from the
// Authorization header with Bearer prefix.
func TestRegression_CookieBasedTokenExtraction(t *testing.T) {
	var (
		logger   = zaptest.NewLogger(t)
		store    = memory.NewStore()
		listener = bufconn.Listen(1024 * 1024)
		server   = grpc.NewServer(
			grpc_middleware.WithUnaryServerChain(
				auth.UnaryInterceptor(logger, store),
				middleware.ErrorUnaryInterceptor,
			),
		)
		errC     = make(chan error)
		shutdown = func(t *testing.T) {
			t.Helper()
			server.Stop()
			if err := <-errC; err != nil {
				t.Fatal(err)
			}
		}
	)

	defer shutdown(t)

	authrpc.RegisterAuthenticationServiceServer(server, auth.NewServer(logger, store))

	go func() {
		errC <- server.Serve(listener)
	}()

	ctx := context.Background()
	dialer := func(context.Context, string) (net.Conn, error) {
		return listener.Dial()
	}

	// Create a valid authentication token
	req := &storageauth.CreateAuthenticationRequest{
		Method:    authrpc.Method_METHOD_TOKEN,
		ExpiresAt: timestamppb.New(time.Now().Add(time.Hour).UTC()),
	}

	clientToken, authentication, err := store.CreateAuthentication(ctx, req)
	require.NoError(t, err)
	require.NotEmpty(t, clientToken)
	require.NotNil(t, authentication)

	conn, err := grpc.DialContext(ctx, "", grpc.WithInsecure(), grpc.WithContextDialer(dialer))
	require.NoError(t, err)
	defer conn.Close()

	client := authrpc.NewAuthenticationServiceClient(conn)

	t.Run("authorization_header_with_bearer_token_succeeds", func(t *testing.T) {
		// This works - the standard case with Bearer token in Authorization header
		authCtx := metadata.AppendToOutgoingContext(
			ctx,
			"authorization",
			"Bearer "+clientToken,
		)
		retrievedAuth, err := client.GetAuthenticationSelf(authCtx, &emptypb.Empty{})
		require.NoError(t, err)
		require.Equal(t, authentication.Id, retrievedAuth.Id)
	})

	t.Run("cookie_based_token_extraction_fails", func(t *testing.T) {
		// BUG: This should work but doesn't - cookies are not extracted by the middleware
		// In a real HTTP/browser scenario, the cookie would be sent automatically by the browser
		// but the middleware doesn't look for tokens in cookies, only in the Authorization header.
		//
		// The middleware only checks: md.Get(authenticationHeaderKey) where authenticationHeaderKey = "authorization"
		// It does NOT check for tokens in gRPC metadata from HTTP cookies or any other source.
		//
		// In gRPC-web or browser contexts, cookies need to be manually converted to metadata,
		// which the current implementation doesn't do.

		// Attempt 1: Try to pass the token as if it came from a cookie
		// This simulates what would happen if HTTP cookies were properly converted to gRPC metadata
		cookieCtx := metadata.AppendToOutgoingContext(
			ctx,
			"cookie",
			"flipt_client_token="+clientToken,
		)
		_, err := client.GetAuthenticationSelf(cookieCtx, &emptypb.Empty{})
		// BUG: This fails because the middleware doesn't check cookies
		require.Error(t, err, "Expected authentication to fail because middleware doesn't extract tokens from cookies")

		// Attempt 2: Try without any authentication
		_, err = client.GetAuthenticationSelf(ctx, &emptypb.Empty{})
		// Also fails as expected
		require.Error(t, err)
	})

	t.Run("missing_bearer_prefix_fails", func(t *testing.T) {
		// This fails because Bearer prefix is required
		authCtx := metadata.AppendToOutgoingContext(
			ctx,
			"authorization",
			clientToken,
		)
		_, err := client.GetAuthenticationSelf(authCtx, &emptypb.Empty{})
		require.Error(t, err)
	})

	t.Run("no_authentication_fails", func(t *testing.T) {
		// Without any authentication, requests are rejected
		_, err := client.GetAuthenticationSelf(ctx, &emptypb.Empty{})
		require.Error(t, err)
	})
}

// TestRegression_ServerSkipAuthenticationNotSupported demonstrates the bug where
// there is no mechanism to selectively skip authentication for specific server instances.
// The authentication middleware is applied globally to all servers based on the
// cfg.Authentication.Required setting, with no per-server override capability.
func TestRegression_ServerSkipAuthenticationNotSupported(t *testing.T) {
	var (
		logger   = zaptest.NewLogger(t)
		store    = memory.NewStore()
		listener = bufconn.Listen(1024 * 1024)
		// This server has authentication middleware enabled
		serverWithAuth = grpc.NewServer(
			grpc_middleware.WithUnaryServerChain(
				auth.UnaryInterceptor(logger, store),
				middleware.ErrorUnaryInterceptor,
			),
		)
		errC     = make(chan error)
		shutdown = func(t *testing.T) {
			t.Helper()
			serverWithAuth.Stop()
			if err := <-errC; err != nil {
				t.Fatal(err)
			}
		}
	)

	defer shutdown(t)

	authrpc.RegisterAuthenticationServiceServer(serverWithAuth, auth.NewServer(logger, store))

	go func() {
		errC <- serverWithAuth.Serve(listener)
	}()

	ctx := context.Background()
	dialer := func(context.Context, string) (net.Conn, error) {
		return listener.Dial()
	}

	// Create a valid authentication token
	req := &storageauth.CreateAuthenticationRequest{
		Method:    authrpc.Method_METHOD_TOKEN,
		ExpiresAt: timestamppb.New(time.Now().Add(time.Hour).UTC()),
	}

	clientToken, _, err := store.CreateAuthentication(ctx, req)
	require.NoError(t, err)

	conn, err := grpc.DialContext(ctx, "", grpc.WithInsecure(), grpc.WithContextDialer(dialer))
	require.NoError(t, err)
	defer conn.Close()

	client := authrpc.NewAuthenticationServiceClient(conn)

	t.Run("all_servers_require_authentication_when_enabled", func(t *testing.T) {
		// BUG: There is no mechanism to skip authentication for specific servers
		// The authentication middleware is applied globally to all servers.
		// When cfg.Authentication.Required is true, ALL services get the middleware.
		// There's no way to say "skip authentication for this particular server instance"
		// (e.g., for delegated auth servers that need to operate without auth checks).

		// Even though we have a valid token, attempting to call GetAuthenticationSelf
		// without authentication fails
		_, err := client.GetAuthenticationSelf(ctx, &emptypb.Empty{})
		require.Error(t, err)

		// The authentication server cannot be configured to skip the middleware
		// You cannot do something like:
		// - server.RegisterService(..., serviceThatSkipsAuth=true)
		// - grpc.NewServer(auth.UnaryInterceptor(logger, store, skipFor=[]string{"SomeService"}))
		//
		// The interceptor doesn't have a field or parameter to skip specific services.
		// It's either on for everything or off for everything (controlled by cfg.Authentication.Required).

		// This limitation prevents scenarios where:
		// 1. Internal delegated authentication flows need to run without auth
		// 2. Health check endpoints shouldn't require authentication
		// 3. Bootstrap/setup endpoints should be accessible without credentials
		// 4. Service-to-service authentication needs different rules than client auth

		// Workaround doesn't exist in the current codebase - you'd need to:
		// - Run separate gRPC servers (one with auth, one without) - not practical
		// - Modify the middleware to check specific services - not implemented
		// - Use a different authentication approach per service - not supported
	})

	t.Run("no_per_server_authentication_configuration", func(t *testing.T) {
		// Verify that we cannot configure authentication to skip for specific service names
		// The UnaryInterceptor signature is:
		// func UnaryInterceptor(logger *zap.Logger, authenticator Authenticator) grpc.UnaryServerInterceptor
		//
		// There's no parameter to specify:
		// - skipServices []string
		// - skipMethods map[string]bool
		// - authenticateFunc func(service string) bool
		//
		// Therefore, it's impossible to skip authentication for specific servers or services.

		// This test simply verifies the limitation exists
		require.True(t, true, "Per-server authentication skip is not supported")
	})

	t.Run("authentication_applies_to_all_operations", func(t *testing.T) {
		// Demonstrate that authentication is applied uniformly to all operations
		// when enabled, with no exception mechanism
		authCtx := metadata.AppendToOutgoingContext(
			ctx,
			"authorization",
			"Bearer "+clientToken,
		)

		// With valid token, call succeeds
		result, err := client.GetAuthenticationSelf(authCtx, &emptypb.Empty{})
		require.NoError(t, err)
		require.NotNil(t, result)

		// Without token, it fails - no bypass possible
		_, err = client.GetAuthenticationSelf(ctx, &emptypb.Empty{})
		require.Error(t, err)

		// There's no way to configure even one server to bypass authentication
		// All services registered on a server share the same middleware chain
	})
}

// TestRegression_AuthenticationHeaderOnlySource demonstrates that the
// authentication middleware ONLY accepts tokens from the Authorization header.
// It does NOT support:
// 1. Extracting tokens from HTTP cookies (flipt_client_token)
// 2. Extracting tokens from custom gRPC metadata headers
// 3. Any fallback mechanism if Authorization header is missing
func TestRegression_AuthenticationHeaderOnlySource(t *testing.T) {
	var (
		logger   = zaptest.NewLogger(t)
		store    = memory.NewStore()
		listener = bufconn.Listen(1024 * 1024)
		server   = grpc.NewServer(
			grpc_middleware.WithUnaryServerChain(
				auth.UnaryInterceptor(logger, store),
				middleware.ErrorUnaryInterceptor,
			),
		)
		errC     = make(chan error)
		shutdown = func(t *testing.T) {
			t.Helper()
			server.Stop()
			if err := <-errC; err != nil {
				t.Fatal(err)
			}
		}
	)

	defer shutdown(t)

	authrpc.RegisterAuthenticationServiceServer(server, auth.NewServer(logger, store))

	go func() {
		errC <- server.Serve(listener)
	}()

	ctx := context.Background()
	dialer := func(context.Context, string) (net.Conn, error) {
		return listener.Dial()
