		shutdown = func(t *testing.T) {
			t.Helper()
			serverWithAuth.Stop()
			if err := <-errC; err != nil {
				t.Fatal(err)
			}
		}
	)

	defer shutdown(t)

	authrpc.RegisterAuthenticationServiceServer(serverWithAuth, auth.NewServer(logger, store))

	go func() {
		errC <- serverWithAuth.Serve(listener)
	}()

