			t.Helper()
			server.Stop()
			if err := <-errC; err != nil {
				t.Fatal(err)
			}
		}
	)

	defer shutdown(t)

	authrpc.RegisterAuthenticationServiceServer(server, auth.NewServer(logger, store))

	go func() {
		errC <- server.Serve(listener)
	}()

	ctx := context.Background()
	dialer := func(context.Context, string) (net.Conn, error) {
		return listener.Dial()
	}

	// Create a valid authentication token
	req := &storageauth.CreateAuthenticationRequest{
		Method:    authrpc.Method_METHOD_TOKEN,
		ExpiresAt: timestamppb.New(time.Now().Add(time.Hour).UTC()),
	}

	clientToken, _, err := store.CreateAuthentication(ctx, req)
	require.NoError(t, err)

	conn, err := grpc.DialContext(ctx, "", grpc.WithInsecure(), grpc.WithContextDialer(dialer))
	require.NoError(t, err)
	defer conn.Close()

	client := authrpc.NewAuthenticationServiceClient(conn)

	t.Run("only_authorization_header_is_checked", func(t *testing.T) {
		// The middleware implementation (in internal/server/auth/middleware.go:51)
		// does this and ONLY this:
		//   authenticationHeader := md.Get(authenticationHeaderKey)
		// where authenticationHeaderKey = "authorization"
		//
		// It does NOT check:
		// - md.Get("cookie")
		// - md.Get("x-auth-token")
		// - md.Get("x-client-token")
		// - Any other header or metadata field

		// Try with custom header - should fail
		customHeaderCtx := metadata.AppendToOutgoingContext(
			ctx,
			"x-client-token",
			"Bearer "+clientToken,
		)
		_, err := client.GetAuthenticationSelf(customHeaderCtx, &emptypb.Empty{})
		require.Error(t, err)

		// Try with lowercase authorization (might work or not due to case sensitivity)
		lowercaseCtx := metadata.AppendToOutgoingContext(
			ctx,
			"authorization",
			"Bearer "+clientToken,
		)
		// This should work - grpc metadata is case-insensitive
		result, err := client.GetAuthenticationSelf(lowercaseCtx, &emptypb.Empty{})
		require.NoError(t, err)
		require.NotNil(t, result)
	})

	t.Run("bearer_prefix_is_required", func(t *testing.T) {
		// The middleware (middleware.go:57) does:
		//   clientToken := strings.TrimPrefix(authenticationHeader[0], "Bearer ")
		// Then validates (middleware.go:59):
		//   if authenticationHeader[0] == clientToken { ... return error }
		//
		// This means:
		// - Token MUST be prefixed with "Bearer " (case-sensitive, with space)
		// - "bearer" (lowercase) would fail
		// - "BEARER" (uppercase) would fail
		// - Just the token without prefix would fail

		// Test with lowercase "bearer"
		lowercaseCtx := metadata.AppendToOutgoingContext(
			ctx,
			"authorization",
			"bearer "+clientToken,
		)
		_, err := client.GetAuthenticationSelf(lowercaseCtx, &emptypb.Empty{})
		require.Error(t, err, "lowercase 'bearer' prefix should fail")

		// Test with just the token (no prefix)
		noPrefixCtx := metadata.AppendToOutgoingContext(
			ctx,
			"authorization",
			clientToken,
		)
		_, err = client.GetAuthenticationSelf(noPrefixCtx, &emptypb.Empty{})
		require.Error(t, err, "token without 'Bearer ' prefix should fail")

		// Test with "Bearer" without space before token
		noSpaceCtx := metadata.AppendToOutgoingContext(
			ctx,
			"authorization",
			"Bearer"+clientToken,
		)
		_, err = client.GetAuthenticationSelf(noSpaceCtx, &emptypb.Empty{})
		require.Error(t, err, "no space after Bearer should fail")

		// Only "Bearer " (with space, exact case) works
		correctCtx := metadata.AppendToOutgoingContext(
			ctx,
			"authorization",
			"Bearer "+clientToken,
		)
		result, err := client.GetAuthenticationSelf(correctCtx, &emptypb.Empty{})
