		// The middleware does NOT have a fallback like:
		// "If authorization header is missing, check cookies"
		// "If authorization header is invalid, check x-api-key"
		// etc.
		//
		// Line 51-55 of middleware.go:
		//   authenticationHeader := md.Get(authenticationHeaderKey)
		//   if len(authenticationHeader) < 1 {
		//       logger.Error("unauthenticated", zap.String("reason", "no authorization provided"))
		//       return ctx, errUnauthenticated
		//   }
		//
		// As soon as authorization header is missing, it returns error.
		// No fallback is attempted.

		// Even if we provide a cookie, it won't be checked as fallback
		ctxWithMultiple := metadata.NewOutgoingContext(ctx, metadata.Pairs(
			"cookie", "flipt_client_token="+clientToken,
			"x-client-token", "Bearer "+clientToken,
		))
		_, err := client.GetAuthenticationSelf(ctxWithMultiple, &emptypb.Empty{})
		require.Error(t, err, "no fallback mechanism exists even with multiple auth sources")
	})
}
